# Transition Effect Helper
def transition_to(stage):
    placeholder = st.empty()
    with placeholder.container():
        st.markdown("""
        <style>
        .transition-overlay {
            position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
            background: #010805; z-index: 9999; display: flex;
            flex-direction: column; align-items: center; justify-content: center;
        }
        .scan-bar {
            width: 300px; height: 2px; background: #d4af37;
            box-shadow: 0 0 20px #d4af37; animation: scanPulse 1.5s infinite;
        }
        @keyframes scanPulse { 0%, 100% { opacity: 0.3; transform: scaleX(0.8); } 50% { opacity: 1; transform: scaleX(1.1); } }
        </style>
        <div class="transition-overlay">
            <div style="color: #d4af37; font-family: 'Outfit'; font-size: 1.2rem; margin-bottom: 15px; letter-spacing: 5px;">ESTABLISHING CONNECTION</div>
            <div class="scan-bar"></div>
        </div>
        """, unsafe_allow_html=True)
        time.sleep(1.2)
    placeholder.empty()
    st.session_state.app_stage = stage
    st.rerun()

# Improved function to handle real login
def handle_login(username, password):
    success, message = db_manager.authenticate_user(username, password)
    if success:
        with st.status("🔐 Establishing Secure Session...", expanded=False) as status:
            import time
            time.sleep(1)
            status.update(label="✅ Authentication Successful!", state="complete", expanded=False)
        
        st.session_state.authenticated = True
        st.session_state.user_email = username
        st.session_state.entered_dashboard = True
        st.rerun()
    else:
        st.error(f"❌ {message}")

# Function to handle real registration
def handle_registration(username, password, confirm_password):
    if not username or not password:
        st.error("Please fill in all fields.")
        return
    
    if password != confirm_password:
        st.error("Passwords do not match.")
        return
    
    if len(password) < 6:
        st.error("Password must be at least 6 characters.")
        return

    success, message = db_manager.register_user(username, password)
    if success:
        st.success(f"✅ {message}")
        st.session_state.auth_mode = "Login"
        time.sleep(1)
        st.rerun()
    else:
        st.error(f"❌ {message}")

# Function to handle logout
def handle_logout():
    st.session_state.authenticated = False
    st.session_state.user_email = None
    st.session_state.entered_dashboard = False
    st.session_state.app_stage = "auth"
    st.rerun()


