def _chatbot_respond(user_msg):
    msg = user_msg.lower().strip()
    
    # Try Groq API first
    try:
        # Eagerly load .env every time to ensure the key is present
        try:
            from dotenv import load_dotenv
            load_dotenv(Path(__file__).parent.parent / ".env")
        except Exception:
            pass  # dotenv not installed or .env missing — still try env var
        
        try:
            _groq_key = st.secrets.get("GROQ_API_KEY", os.environ.get("GROQ_API_KEY", ""))
        except Exception:
            _groq_key = os.environ.get("GROQ_API_KEY", "")
        if _groq_key:
            from groq import Groq
            client = Groq(api_key=_groq_key)
            
            system_prompt = """You are WildGuard AI Assistant, a specialized chatbot for endangered species conservation. 
            Keep responses incredibly concise (2 sentences max). Focus heavily on wildlife conservation, endangered species, 
            ecosystem health, and biodiversity. If asked about non-wildlife topics, politely redirect to conservation.
            You know about: Bengal Tiger, Indian Elephant, Indian Rhinoceros, Snow Leopard, 
            Asiatic Lion, Indian Wild Dog, Ganges River Dolphin, Indian Pangolin, Great Indian Bustard."""
            
            chat_completion = client.chat.completions.create(
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_msg}
                ],
                model="llama-3.1-8b-instant",
                temperature=0.5,
            )
            return chat_completion.choices[0].message.content
        else:
            print("⚠️ GROQ_API_KEY not found in environment or .env file")
    except Exception as e:
        print(f"Groq API Error: {e}")
    
    # Fallback: rule-based
    for key, info in _species_kb.items():
        if key in msg:
            if any(w in msg for w in ["role", "ecosystem", "what does", "function"]):
                return f"**{info['name']} — Ecosystem Role:** {info['role']}"
            elif any(w in msg for w in ["why", "matter", "important"]):
                return f"**Why {info['name']} Matters:** {info['why']}"
            elif any(w in msg for w in ["population", "how many", "number", "left"]):
                return f"**{info['name']}:** {info['pop']} | Status: {info['status']}"
            else:
                return f"**{info['name']}** ({info['status']})\n\n{info['pop']}\n\n**Role:** {info['role']}\n\n**Why it matters:** {info['why']}"
    
    if any(w in msg for w in ["hello", "hi", "hey"]):
        return "Hello! I'm Prakriti 🌿 Your wildlife conservation guide. Ask me about any endangered species — their population, ecosystem role, or why they matter!"
    elif any(w in msg for w in ["help", "what can you"]):
        return "I can help with: species info, ecosystem roles, conservation urgency, and population data. Try: *Tell me about the Bengal Tiger*"
    elif any(w in msg for w in ["most endangered", "critical"]):
        return "The **Great Indian Bustard** (fewer than 150 left) and the **Asiatic Lion** (~700, all in one forest) are among the most critical."
    elif any(w in msg for w in ["list", "all species"]):
        return "\n".join([f"• **{v['name']}** — {v['status']}" for v in _species_kb.values()])
    elif any(w in msg for w in ["thank", "thanks", "bye"]):
        return "You're welcome! Every species saved strengthens our planet 🌍"
    else:
        return "I can tell you about endangered species! Try: *Tell me about the Snow Leopard* or *Why does the Indian Elephant matter?*"

# Initialize chat
