with st.popover("🌿 Ask Prakriti"):
    st.markdown("<h3 style='margin-top: 0; color: #10b981; font-family: Inter, sans-serif; font-weight: 600;'>🌿 Ask Prakriti</h3>", unsafe_allow_html=True)
    st.markdown("<p style='font-size: 0.85rem; color: rgba(255,255,255,0.6); margin-top: -10px; margin-bottom: 20px;'>Wildlife Conservation AI • Powered by Groq</p>", unsafe_allow_html=True)
    
    chat_container = st.container(height=350)
    with chat_container:
        for message in st.session_state.float_chat:
            with st.chat_message(message["role"]):
                st.markdown(message["content"])
    
    if user_input := st.chat_input("Ask about endangered wildlife...", key="float_chat_input"):
        st.session_state.float_chat.append({"role": "user", "content": user_input})
        with chat_container:
            with st.chat_message("user"):
                st.markdown(user_input)
            with st.chat_message("assistant"):
                with st.spinner("Prakriti is typing..."):
                    response = _chatbot_respond(user_input)
                st.markdown(response)
        st.session_state.float_chat.append({"role": "assistant", "content": response})
        st.rerun()
